mapper.select:
select *
from batch.file_record
where tenant_id = #{tenantId}
  and id = #{fileId}

select *
from batch.file_channel_config
where tenant_id = #{tenantId}
  and channel_code = #{channelCode}
  and is_deleted = false

select *
from batch.file_dispatch_record
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and channel_code = #{channelCode}
order by id desc
limit 1

mapper.insert:
insert into batch.file_dispatch_record (
    tenant_id, file_id, pipeline_instance_id, channel_code, dispatch_target, dispatch_status,
    dispatch_attempt, receipt_code, receipt_status, external_request_id
) values (
    #{tenantId}, #{fileId}, #{pipelineInstanceId}, #{channelCode}, #{dispatchTarget}, #{dispatchStatus},
    1, #{receiptCode}, #{receiptStatus}, #{externalRequestId}
)

mapper.update:
update batch.file_dispatch_record
set dispatch_attempt = dispatch_attempt + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and channel_code = #{channelCode}

update batch.file_dispatch_record
set dispatch_status = #{dispatchStatus},
    external_request_id = #{externalRequestId},
    receipt_code = coalesce(#{receiptCode}, receipt_code),
    receipt_status = #{receiptStatus},
    dispatched_at = current_timestamp,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and channel_code = #{channelCode}

update batch.file_dispatch_record
set dispatch_status = #{dispatchStatus},
    receipt_status = #{receiptStatus},
    receipt_code = #{receiptCode},
    ack_at = current_timestamp,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and channel_code = #{channelCode}

  and dispatch_status = #{expectedDispatchStatus}

update batch.file_dispatch_record
set dispatch_status = #{dispatchStatus},
    receipt_status = #{receiptStatus},
    error_code = #{errorCode},
    error_message = #{errorMessage},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and channel_code = #{channelCode}

mapper.select:
select *
from batch.file_dispatch_record
where dispatch_status = #{dispatchStatus}
  and receipt_status = #{receiptStatus}
  and dispatched_at > now() - make_interval(secs => #{maxAgeSeconds})
order by dispatched_at asc nulls last
limit #{limit}

mapper.update:
update batch.file_dispatch_record
set dispatch_status = #{dispatchStatus},
    receipt_status = case
        when receipt_status = #{receiptStatusSuccess} then receipt_status
        else #{receiptStatusFailed}
    end,
    error_code = #{errorCode},
    error_message = #{errorMessage},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and channel_code = #{channelCode}
